import m_001 from './m_001_hard.rs';
import m_002 from './m_002_hard.rs';
import m_003 from './m_003_hard.rs';
import m_004 from './m_004_hard.rs';
import m_005 from './m_005_hard.rs';

let arr = [m_001, m_002, m_003, m_004, m_005];

let aqoursHardBeatmap = [];
arr.forEach((path) => {
  fetch(path)
    .then((rs) => rs.json())
    .then((data) => aqoursHardBeatmap.push(data));
});

export default aqoursHardBeatmap;
